import logging
import time
import datetime

# Настройка логирования
logging.basicConfig(filename='activity.log', level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

class ActivityTracker:
    def __init__(self):
        self.activity_log = []

    def start_activity(self, activity_name):
        logging.info(f'Начата активность: {activity_name}')
        self.activity_log.append(f'Начата активность: {activity_name} - {datetime.datetime.now()}')

    def stop_activity(self, activity_name):
        logging.info(f'Окончена активность: {activity_name}')
        self.activity_log.append(f'Окончена активность: {activity_name} - {datetime.datetime.now()}')

    def get_activity_log(self):
        return self.activity_log

def main():
    tracker = ActivityTracker()

    while True:
        print('1. Начать активность')
        print('2. Окончить активность')
        print('3. Просмотреть журнал активности')
        print('4. Выход')

        choice = input('Введите номер действия: ')

        if choice == '1':
            activity_name = input('Введите название активности: ')
            tracker.start_activity(activity_name)
        elif choice == '2':
            activity_name = input('Введите название активности: ')
            tracker.stop_activity(activity_name)
        elif choice == '3':
            print('Журнал активности:')
            for activity in tracker.get_activity_log():
                print(activity)
        elif choice == '4':
            break
        else:
            print('Неправильный выбор. Пожалуйста, повторите.')

if __name__ == '__main__':
    main()
```

